    // ============================================================
    // Alpine.js 登録: テーマ切替 / 画像モーダル / fixed-shelf ストア
    // ============================================================
    document.addEventListener('alpine:init', () => {
      const HLJS_BASE = 'https://cdn.jsdelivr.net/npm/@highlightjs/cdn-assets@11/styles/';
      const THEME_KEY = 'theme';
      const lightMQL = matchMedia('(prefers-color-scheme: light)');
      const storedTheme = () => {
        const v = localStorage.getItem(THEME_KEY);
        return v === 'light' || v === 'dark' ? v : null;
      };

      // テーマ切替 (light / dark, 未設定時は OS 設定に追従)
      Alpine.data('themeSwitch', () => ({
        theme: storedTheme() || (lightMQL.matches ? 'light' : 'dark'),
        init() {
          this.apply();
          lightMQL.addEventListener('change', e => {
            if (storedTheme()) return;
            this.theme = e.matches ? 'light' : 'dark';
            this.apply();
          });
        },
        toggle() {
          this.theme = this.theme === 'dark' ? 'light' : 'dark';
          localStorage.setItem(THEME_KEY, this.theme);
          this.apply();
        },
        apply() {
          document.documentElement.setAttribute('data-theme', this.theme);
          const hl = document.querySelector('.js-hljs-theme');
          if (hl) hl.href = HLJS_BASE + (this.theme === 'light' ? 'github.min.css' : 'github-dark.min.css');
        }
      }));

      // 画像モーダル (post-body の img クリックで開く)
      Alpine.data('imageModal', () => ({
        src: '',
        open(src) {
          this.src = src.replace(/s\d{2,4}(-c)?/, 's1600');
          this.$el.showModal();
        },
        close() { this.$el.close(); }
      }));

      // モバイル fixed-shelf の開閉ストア (Esc キーで閉じる)
      Alpine.store('shelf', {
        open: false,
        toggle() { this.open = !this.open; },
        close() { this.open = false; },
        init() {
          addEventListener('keydown', e => {
            if (e.key === 'Escape') this.close();
          });
        }
      });

      // タグ一覧ポップオーバーのストア (サイドバーの .labels を複製して表示)
      Alpine.store('tagList', {
        open: false,
        toggle() {
          this.open = !this.open;
          if (this.open) this.populate();
        },
        close() { this.open = false; },
        populate() {
          const src = document.querySelector('aside .labels');
          const dst = document.querySelector('.js-tag-list-popover');
          if (!src || !dst || dst.childElementCount) return;
          dst.innerHTML = src.innerHTML;
        }
      });
    });

    // ============================================================
    // 起動: 個別記事ページの後処理
    // ============================================================
    document.addEventListener('DOMContentLoaded', () => {
      renderMarkdown();
      buildTOC();
      setupTOCHighlight();
      loadLinkCards();
      syncHgroupHeight();
    });

    function syncHgroupHeight() {
      const hgroup = document.querySelector('body > header hgroup');
      const header = document.querySelector('body > header');
      if (!hgroup || !header) return;
      const update = () => header.style.setProperty('--hgroup-h', hgroup.offsetHeight + 'px');
      new ResizeObserver(update).observe(hgroup);
      update();
    }

    // 本文を markdown-it でレンダリング
    // (Blogger は本文を <p> で勝手に包むので除去してから渡す)
    function renderMarkdown() {
      const el = document.querySelector('.markdown');
      if (!el) return;
      const md = window.markdownit({
        html: true,
        linkify: true,
        typographer: true,
        langPrefix: 'hljs language-'
      }).use(window.markdownitEmoji);
      const src = el.innerHTML
        .replace(/<p[^>]*>\s*/gi, '')
        .replace(/\s*<\/p>/gi, '\n\n');
      el.innerHTML = md.render(src);
      el.querySelectorAll('pre code').forEach(b => hljs.highlightElement(b));
      twemoji.parse(el, { base: 'https://cdn.jsdelivr.net/gh/twitter/twemoji@v14.0.2/assets/' });
    }

    // 見出しから目次ツリーを生成
    function buildTOC() {
      const body = document.querySelector('.post-body');
      const nav = document.querySelector('.content-toc > nav');
      if (!body || !nav) return;
      const headings = body.querySelectorAll('h2, h3, h4');
      if (!headings.length) return;

      const root = document.createElement('ul');
      const stack = [];
      headings.forEach((el, i) => {
        if (!el.id) el.id = 'toc-' + i;
        const level = parseInt(el.tagName[1]);
        const li = document.createElement('li');
        const a = document.createElement('a');
        a.href = '#' + el.id;
        a.textContent = el.textContent.trim();
        li.appendChild(a);

        while (stack.length && stack[stack.length - 1].level >= level) stack.pop();
        if (!stack.length) {
          root.appendChild(li);
        } else {
          const parent = stack[stack.length - 1].li;
          let sub = parent.querySelector('ul');
          if (!sub) {
            sub = document.createElement('ul');
            parent.appendChild(sub);
          }
          sub.appendChild(li);
        }
        stack.push({ level, li });
      });
      nav.appendChild(root);
    }

    // スクロール位置に応じて目次の現在地を aria-current でハイライト
    function setupTOCHighlight() {
      const nav = document.querySelector('.content-toc > nav');
      if (!nav) return;
      const links = nav.querySelectorAll('a');
      const headings = document.querySelectorAll('.post-body h2, .post-body h3, .post-body h4');
      if (!headings.length) return;

      let lastActive = null;
      addEventListener('scroll', () => {
        let currentId = null;
        headings.forEach(h => {
          if (scrollY >= h.getBoundingClientRect().top + scrollY - 225) currentId = h.id;
        });
        links.forEach(a => {
          a.removeAttribute('aria-current');
          if (currentId && a.getAttribute('href') === '#' + currentId) {
            a.setAttribute('aria-current', 'true');
            if (lastActive !== a) {
              lastActive = a;
              nav.scrollTo({ top: a.offsetTop - nav.clientHeight / 2, behavior: 'smooth' });
            }
          }
        });
      });
    }

    // リンクカード (Microlink + localStorage キャッシュ + IntersectionObserver 遅延ロード)
    function loadLinkCards() {
      const CACHE_PREFIX = 'ogp:';
      const CACHE_TTL = 7 * 24 * 60 * 60 * 1000;

      const getCached = url => {
        try {
          const raw = localStorage.getItem(CACHE_PREFIX + url);
          if (!raw) return null;
          const obj = JSON.parse(raw);
          if (Date.now() - obj.ts > CACHE_TTL) {
            localStorage.removeItem(CACHE_PREFIX + url);
            return null;
          }
          return obj.data;
        } catch { return null; }
      };

      const setCached = (url, data) => {
        const payload = JSON.stringify({ ts: Date.now(), data });
        try {
          localStorage.setItem(CACHE_PREFIX + url, payload);
        } catch {
          // 容量不足: 既存 OGP キャッシュを掃除して再試行
          try {
            Object.keys(localStorage).forEach(k => {
              if (k.startsWith(CACHE_PREFIX)) localStorage.removeItem(k);
            });
            localStorage.setItem(CACHE_PREFIX + url, payload);
          } catch {}
        }
      };

      const buildCard = (href, d) => {
        const card = document.createElement('a');
        card.className = 'link-card';
        card.href = href;
        card.target = '_blank';
        card.rel = 'noopener noreferrer';

        const body = document.createElement('div');
        const title = document.createElement('strong');
        title.textContent = d.title || href;
        body.appendChild(title);

        if (d.description) {
          const desc = document.createElement('small');
          desc.textContent = d.description;
          body.appendChild(desc);
        }

        const meta = document.createElement('small');
        if (d.logo && d.logo.url) {
          const fav = document.createElement('img');
          fav.src = d.logo.url;
          fav.alt = '';
          fav.onerror = function () { this.style.display = 'none'; };
          meta.appendChild(fav);
        }
        try { meta.appendChild(document.createTextNode(new URL(href).hostname)); }
        catch { meta.appendChild(document.createTextNode(href)); }
        body.appendChild(meta);
        card.appendChild(body);

        if (d.image && d.image.url) {
          const img = document.createElement('img');
          img.src = d.image.url;
          img.alt = '';
          img.loading = 'lazy';
          card.appendChild(img);
        }
        return card;
      };

      const renderCard = (href, p, data) => {
        p.parentNode.insertBefore(buildCard(href, data), p.nextSibling);
      };

      const fetchCard = (href, p) => {
        const cached = getCached(href);
        if (cached) { renderCard(href, p, cached); return; }
        fetch('https://api.microlink.io/?url=' + encodeURIComponent(href))
          .then(r => r.json())
          .then(json => {
            if (json.status !== 'success') return;
            setCached(href, json.data);
            renderCard(href, p, json.data);
          })
          .catch(() => {});
      };

      // <p> 直下に裸で置かれた http(s) リンクのみカード化
      const targets = [];
      document.querySelectorAll('.post-body a[href]').forEach(a => {
        const href = a.getAttribute('href');
        if (!href || !href.startsWith('http')) return;
        const p = a.closest('p');
        if (!p) return;
        targets.push({ a, href, p });
      });

      if ('IntersectionObserver' in window) {
        const io = new IntersectionObserver(entries => {
          entries.forEach(entry => {
            if (!entry.isIntersecting) return;
            io.unobserve(entry.target);
            const t = entry.target.__linkCardTarget;
            if (t) fetchCard(t.href, t.p);
          });
        }, { rootMargin: '1500px' });
        targets.forEach(t => {
          t.a.__linkCardTarget = t;
          io.observe(t.a);
        });
      } else {
        targets.forEach(t => fetchCard(t.href, t.p));
      }
    }

    // ============================================================
    // インセンティブ表示
    // ============================================================
